                .build();
    }

    private static ChatCompletionResponse response(ToolCall... toolCalls) {
        return ChatCompletionResponse.builder()
                .id("resp_1")
                .model("openai-compatible-model")
                .choices(List.of(ChatCompletionChoice.builder()
                        .index(0)
                        .delta(Delta.builder().toolCalls(List.of(toolCalls)).build())
                        .build()))
                .build();
    }

    private static void assertRequests(ChatResponse response, String... ids) {
        List<ToolExecutionRequest> requests = response.aiMessage().toolExecutionRequests();
        String actualIds = requests.stream().map(ToolExecutionRequest::id).collect(Collectors.joining(","));
        String expectedIds = String.join(",", ids);
        System.out.println("size=" + requests.size() + " ids=" + actualIds);
        if (requests.size() != ids.length || !expectedIds.equals(actualIds)) {
            throw new AssertionError("Expected " + expectedIds + ", got " + requests);
        }
    }
}
